$base = "$env:USERPROFILE\Desktop\AssetManagement"
$enc  = [System.Text.Encoding]::UTF8
Write-Host "Stage 6 fixes..." -ForegroundColor Cyan

# ReportsController.cs
$p = "$base\AssetManagement.Web\Controllers\ReportsController.cs"
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: ReportsController.cs" -ForegroundColor Green

# ExcelImportService.cs
$p = "$base\AssetManagement.Application\Services\ExcelImportService.cs"
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: ExcelImportService.cs" -ForegroundColor Green

# Fix ContractsController.DownloadWord - use GetByIdAsync to load RentalRequests
$cpath = "$base\AssetManagement.Web\Controllers\ContractsController.cs"
$c = [System.IO.File]::ReadAllText($cpath, $enc)
$oldDl = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
$newDl = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if ($c.Contains($oldDl)) {
    $c = $c.Replace($oldDl, $newDl)
    [System.IO.File]::WriteAllText($cpath, $c, $enc)
    Write-Host "  OK: ContractsController DownloadWord fixed" -ForegroundColor Green
} else { Write-Host "  INFO: DownloadWord already fixed or different" -ForegroundColor Yellow }

# Add DeleteAll action to AssetController
$ap = "$base\AssetManagement.Web\Controllers\AssetController.cs"
$c = [System.IO.File]::ReadAllText($ap, $enc)
$delAll = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if (-not $c.Contains("DeleteAll")) {
    # Insert before the last closing brace
    $lastBrace = $c.LastIndexOf("}")
    $c = $c.Substring(0, $lastBrace) + $delAll + $c.Substring($lastBrace)
    [System.IO.File]::WriteAllText($ap, $c, $enc)
    Write-Host "  OK: DeleteAll added to AssetController" -ForegroundColor Green
} else { Write-Host "  INFO: DeleteAll already exists" -ForegroundColor Yellow }

cd $base
dotnet build 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Stage 6A done!" -ForegroundColor Green }